challenges.solution:
.container { display: grid; gap: 1rem; }
@media (min-width: 600px) { .container { grid-template-columns: repeat(2, 1fr); } }
@media (min-width: 900px) { .container { grid-template-columns: repeat(3, 1fr); } }

.nav { display: flex; align-items: center; }
.nav-links { display: flex; gap: 1rem; }
.hamburger { display: none; }
@media (max-width: 768px) {
  .hamburger { display: block; }
  .nav-links { display: none; position: absolute; top: 60px; left: 0; width: 100%; flex-direction: column; background: white; }
  .nav-links.active { display: flex; }
}

.dashboard { display: grid; grid-template-areas: 'header' 'main' 'sidebar'; grid-template-columns: 1fr; }
@media (min-width: 768px) { .dashboard { grid-template-areas: 'header header' 'sidebar main'; grid-template-columns: 200px 1fr; } }
@media (min-width: 1200px) { .dashboard { grid-template-areas: 'sidebar header header' 'sidebar main widgets'; grid-template-columns: 200px 1fr 300px; } }
